#include <iostream>
#include <iomanip>
#include <string>

int main()
{
    using std::cout;
    using std::cin;
    using std::string;

    int total{};

    // Item 1
    {
        string name{};
        int cents{};
        cin >> name >> cents;
        int dollars = cents / 100;
        int rem     = cents % 100;
        cout << name << ": $" << dollars << '.'
             << std::setw(2) << std::setfill('0') << rem << '\n';
        total += cents;
    }

    // Item 2
    {
        string name{};
        int cents{};
        cin >> name >> cents;
        int dollars = cents / 100;
        int rem     = cents % 100;
        cout << name << ": $" << dollars << '.'
             << std::setw(2) << std::setfill('0') << rem << '\n';
        total += cents;
    }

    // Item 3
    {
        string name{};
        int cents{};
        cin >> name >> cents;
        int dollars = cents / 100;
        int rem     = cents % 100;
        cout << name << ": $" << dollars << '.'
             << std::setw(2) << std::setfill('0') << rem << '\n';
        total += cents;
    }

    int tdollars = total / 100;
    int trem     = total % 100;
    cout << "Total: $" << tdollars << '.'
         << std::setw(2) << std::setfill('0') << trem << '\n';

    return 0;
}

